const { client_final_id, montant_ht, montant_ttc, type = 'abonnement', description, stripe_payment_id, tenant_id } = $input.first().json.body;

if (!client_final_id) throw new Error('client_final_id is required');
if (!montant_ht || montant_ht <= 0) throw new Error('montant_ht is required and must be > 0');

const date = new Date();
const mois = `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}`;

return {
  json: {
    client_final_id,
    montant_ht,
    montant_ttc: montant_ttc || montant_ht,
    type,
    description: description || '',
    stripe_payment_id: stripe_payment_id || null,
    tenant_id: tenant_id || null,
    mois
  }
};

const revenueEvent = $input.first().json;
const client_final_id = revenueEvent.client_final_id;

const query = `
SELECT 
  cf.id,
  cf.partner_id,
  cf.apporteur_client_id,
  p1.commission_taux_niveau1,
  p1.commission_taux_niveau2,
  cf.nom as client_name,
  p1.nom as partner_name
FROM client_finals cf
LEFT JOIN partners p1 ON cf.partner_id = p1.id
WHERE cf.id = '${client_final_id}';
`;

return {
  json: {
    query,
    client_final_id,
    montant_ht: revenueEvent.montant_ht,
    type: revenueEvent.type,
    mois: revenueEvent.mois
  }
};

const clientData = $input.first().json[0];
const montant_ht = $input.all()[3].json.montant_ht;
const mois = $input.all()[3].json.mois;
const type = $input.all()[3].json.type;

const statements = [];
const commissions = [];

// Niveau 1: Direct partner
if (clientData.partner_id) {
  const commission_n1 = (montant_ht * clientData.commission_taux_niveau1) / 100;
  statements.push(`INSERT INTO commissions (partner_id, client_final_id, niveau, type, montant_base_ht, taux_applique, montant_commission, statut, mois, created_at) VALUES ('${clientData.partner_id}', '${clientData.id}', 1, '${type}', ${montant_ht}, ${clientData.commission_taux_niveau1}, ${commission_n1}, 'en_attente', '${mois}', NOW());`);
  commissions.push({ niveau: 1, partner_id: clientData.partner_id, amount: commission_n1, partner_name: clientData.partner_name });
  statements.push(`INSERT INTO revenue_events (client_final_id, montant_ht, type, description, mois, created_at) VALUES ('${clientData.id}', -${commission_n1}, 'commission_sortante', 'Commission N1 - ${clientData.partner_name}', '${mois}', NOW());`);
}

// Niveau 2: Apporteur's partner (if exists)
if (clientData.apporteur_client_id) {
  statements.push(`
SELECT cf2.partner_id, p2.commission_taux_niveau2, p2.nom
FROM client_finals cf2
LEFT JOIN partners p2 ON cf2.partner_id = p2.id
WHERE cf2.id = '${clientData.apporteur_client_id}'
  `);
}

return {
  json: {
    statements,
    commissions,
    montant_ht,
    mois,
    client_id: clientData.id,
    client_name: clientData.client_name
  }
};
